package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.finance.*;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;
@RestController @RequestMapping("/api/supplier/v1")public class SupplierFinanceController{private final SupplierFinanceApplicationService service;private final CommandContextFactory contexts;public SupplierFinanceController(SupplierFinanceApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@GetMapping("/reconciliations")public ApiResponse<PageResult<FinanceViews.Reconciliation>> reconciliations(@RequestParam(required=false)Long supplierId,@RequestParam(required=false)Integer status,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ApiResponse.success(service.reconciliations(supplierId,scope(jwt),status,pageNo,pageSize),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@PostMapping("/reconciliations/{id}/confirm")public ApiResponse<Void> confirm(@PathVariable long id,@Valid @RequestBody Confirm b,HttpServletRequest r,Authentication a){service.confirm(id,b.version(),b.confirmedAmount(),b.differenceReason(),contexts.create(r,a));return ok(r);}@PostMapping("/reconciliations/{id}/withdraw")public ApiResponse<Void> withdraw(@PathVariable long id,@Valid @RequestBody Version b,HttpServletRequest r,Authentication a){service.withdraw(id,b.version(),contexts.create(r,a));return ok(r);}@GetMapping("/invoices")public ApiResponse<PageResult<FinanceViews.Invoice>> invoices(@RequestParam(required=false)Long supplierId,@RequestParam(required=false)Integer status,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ApiResponse.success(service.invoices(supplierId,scope(jwt),status,pageNo,pageSize),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@PostMapping("/invoices")public ApiResponse<Long> invoice(@Valid @RequestBody Invoice b,HttpServletRequest r,Authentication a){return ApiResponse.success(service.uploadInvoice(b.invoiceNo(),b.supplierId(),b.reconciliationId(),b.invoiceType(),b.amountExcludingTax(),b.taxAmount(),b.taxRate(),b.attachmentUrl(),contexts.create(r,a)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}private ApiResponse<Void> ok(HttpServletRequest r){return ApiResponse.success(null,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}private Long scope(Jwt j){Number n=j.hasClaim("supplier_id")?j.getClaim("supplier_id"):null;return n==null?null:n.longValue();}public record Confirm(@PositiveOrZero int version,@DecimalMin("0")BigDecimal confirmedAmount,String differenceReason){}public record Version(@PositiveOrZero int version){}public record Invoice(@NotBlank String invoiceNo,@Positive long supplierId,Long reconciliationId,@Min(1)@Max(3)int invoiceType,@DecimalMin("0")BigDecimal amountExcludingTax,@DecimalMin("0")BigDecimal taxAmount,@DecimalMin("0")BigDecimal taxRate,@NotBlank String attachmentUrl){} }
